import Foundation

public actor ClaudeActiveAccountMonitor {
    // 15 s: short enough to react to account switches without hammering the disk.
    // Public so it can be referenced as a default argument value in callers' code.
    public static let defaultInterval: Duration = .seconds(15)

    private let claudeConfigPath: String
    private let fileManager: UsagesFileManager
    private let logger: FileLogger
    private let interval: Duration

    private var monitorTask: Task<Void, Never>?

    private static let monitoredVendor = "claude"

    public init(
        claudeConfigPath: String? = nil,
        fileManager: UsagesFileManager,
        logger: FileLogger = Loggers.claude,
        interval: Duration = ClaudeActiveAccountMonitor.defaultInterval
    ) {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        self.claudeConfigPath = claudeConfigPath ?? "\(home)/.claude.json"
        self.fileManager = fileManager
        self.logger = logger
        self.interval = interval
    }

    public func start() {
        guard monitorTask == nil else {
            logger.log(.warning, "Active-account monitor already running")
            return
        }
        logger.log(.info, "Starting active-account monitor with interval \(interval)")
        monitorTask = Task {
            while !Task.isCancelled {
                await self.checkOnce()
                try? await Task.sleep(for: self.interval)
                guard !Task.isCancelled else { break }
            }
        }
    }

    public func stop() {
        monitorTask?.cancel()
        monitorTask = nil
        logger.log(.info, "Active-account monitor stopped")
    }

    public func checkOnce() async {
        let active = readActiveAccount()
        await fileManager.updateIsActive(vendor: Self.monitoredVendor, activeAccount: active)
        logger.log(.debug, "isActive updated: activeAccount=\(active ?? "<none>")")
    }

    private func readActiveAccount() -> String? {
        guard let data = FileManager.default.contents(atPath: claudeConfigPath) else {
            logger.log(.warning, "Cannot read \(claudeConfigPath)")
            return nil
        }
        do {
            let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
            let oauth = json?["oauthAccount"] as? [String: Any]
            return oauth?["emailAddress"] as? String
        } catch {
            logger.log(.error, "Failed to parse \(claudeConfigPath): \(error)")
            return nil
        }
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("UsagesFileManager")
struct UsagesFileManagerTests {
    private func makeTempDir() -> String {
        let dir = NSTemporaryDirectory() + "ai-tracker-tests-\(UUID().uuidString)"
        try! FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
        return dir
    }

    private func makeManager(dir: String) -> UsagesFileManager {
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        // Uses the internal init accessible via @testable import — production code uses .shared.
        return UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)
    }

    @Test("read returns empty file when no file exists")
    func readMissing() async {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        let result = await mgr.read()
        #expect(result.usages.isEmpty)
    }

    @Test("update creates file and writes entries")
    func updateCreatesFile() async {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        let entry = VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true, metrics: [
            .timeWindow(name: "session", resetAt: "2026-04-17T15:00:00+00:00",
                        windowDurationMinutes: 300, usagePercent: 50),
        ])
        await mgr.update(with: [entry])

        let result = await mgr.read()
        #expect(result.usages.count == 1)
        #expect(result.usages[0].vendor == "claude")
        #expect(result.usages[0].account == "a@b.com")
    }

